document.addEventListener("DOMContentLoaded",function(){const e=document.getElementById("share-article");e&&e.addEventListener("click",function(){navigator.clipboard&&navigator.clipboard.writeText(window.location.href).then(()=>{e.innerHTML;e.innerHTML='<i class="fa-solid fa-check"></i>',e.classList.add("copied"),setTimeout(()=>{e.innerHTML='<i class="fa-solid fa-share"></i>',e.classList.remove("copied")},1500)})})});